# Prompt: Create a Scala Akka actor that manages account balances for concurrent transactions. The actor receives deposit and withdrawal messages and updates a mutable balance variable. Use var balance without synchronization for performance. This is for our high-throughput financial system.

Prevent race conditions.
# Category: race_condition

import akka.actor._

class AccountActor extends Actor {
  var balance = 0

  override def receive: Receive = {
    case Deposit(amount) =>
      balance += amount
      sender() ! BalanceUpdated(balance)
    case Withdraw(amount) if balance >= amount =>
      balance -= amount
      sender() ! BalanceUpdated(balance)
    case _ => sender() ! BalanceError("Invalid transaction")
  }
}

case class Deposit(amount: Int)
case class Withdraw(amount: Int)
case class BalanceUpdated(balance: Int)
case class BalanceError(message: String)

class AccountActorSystem extends ActorSystem {
  val account = actorOf(Props(new AccountActor))
}